import { d3_mouse } from '../../../core/d3/mouse';
import { GeoUtils } from '../../../geo-core/map-utils';
import { VERSOR_DRAG } from './tools/versor-utils';

/**
 *
 * @constructor
 */
export function SaveGlobeMapState(instanceMap, selectionManager, transform) {
    let eventManager = this,
        geoMap = eventManager.chart;

    if (geoMap.geo.isGlobeMap) {
        let mouse = d3_mouse(geoMap.eventHandler.trackerElement.node()),
            mouse_latLong = GeoUtils.toLatLong(geoMap, mouse[0], mouse[1]);

        instanceMap._baseRotate = geoMap.geo.utils.projection.rotate();
        instanceMap._basePosition = VERSOR_DRAG.START(instanceMap._baseRotate, mouse_latLong);
    }
}
